import{_ as t,o as a,c as r,a2 as i}from"./chunks/framework.CKCxdkvf.js";const p=JSON.parse('{"title":"PRD-005 — Earth Orbit Viewer","description":"","frontmatter":{},"headers":[],"relativePath":"prd/PRD-005.md","filePath":"prd/PRD-005.md"}'),o={name:"prd/PRD-005.md"};function s(l,e,h,n,c,d){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="prd-005-—-earth-orbit-viewer" tabindex="-1">PRD-005 — Earth Orbit Viewer <a class="header-anchor" href="#prd-005-—-earth-orbit-viewer" aria-label="Permalink to &quot;PRD-005 — Earth Orbit Viewer&quot;">​</a></h1><blockquote><p>Status · Draft v0.1 Sources · 02_Project_Concept.md §six-screens · 03_Data_Catalog.md §earth-objects Audiences · curious learner, STEM student (PA §audiences) Promises · real physics, educational at every level (PA §promises) Principles · physics first (PA §principles) Why this is a PRD · This screen changes a person&#39;s understanding of how much humanity has already placed around Earth — and makes the logarithmic range of orbital distances viscerally legible in a way that a list of altitudes never does.</p></blockquote><p>A person who knows the ISS is &quot;in space&quot; but has never thought about where JWST is opens this screen. The ISS is at the bottom, close to Earth. The Moon is about two-thirds of the way up. JWST is near the top. The L2 label explains: 1.5 million kilometres. They look back at the ISS: 408 km. The ratio is 3,750 to 1. On a linear scale, the ISS would be invisible. The logarithmic scale makes both legible. They understand something new.</p><h2 id="the-problem" tabindex="-1">The problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The problem&quot;">​</a></h2><p>&quot;Space&quot; is treated as a single location. The ISS, GPS satellites, geostationary TV satellites, the Moon, and JWST are all &quot;in space&quot; — but they occupy regions of near-Earth space that differ by four orders of magnitude in altitude. The vocabulary exists (LEO, MEO, GEO, cislunar, L2) but the spatial relationship is invisible.</p><h2 id="the-experience" tabindex="-1">The experience <a class="header-anchor" href="#the-experience" aria-label="Permalink to &quot;The experience&quot;">​</a></h2><p>The screen shows a vertical logarithmic scale. Earth is at the bottom. Objects are positioned at their correct relative altitudes. The regimes are labelled — Low Earth Orbit, Medium Earth Orbit, Geostationary, Cislunar, L2. The ISS, Hubble, GPS constellation, geostationary belt, the Moon, and JWST are all present.</p><p>The user clicks on JWST. A detail panel opens: altitude 1.5 million km, orbital period 365 days (it orbits the Sun, not Earth, in a halo orbit around L2), primary mirror 6.5m, launch date December 2021. The LEARN tab links to the JWST mission page, the mirror deployment story, and the first light images.</p><p>The user hovers over the geostationary belt. A label explains: at 35,786 km, a satellite&#39;s orbital period matches Earth&#39;s rotation. That&#39;s why TV satellites are stationary in the sky.</p><h2 id="why-now" tabindex="-1">Why now <a class="header-anchor" href="#why-now" aria-label="Permalink to &quot;Why now&quot;">​</a></h2><p>Earth orbit is the context screen — it shows what&#39;s already there before humanity tries to go further. It pairs with the Moon Map (what&#39;s on the lunar surface) to establish the full picture of where humanity has placed hardware.</p><h2 id="success-looks-like" tabindex="-1">Success looks like <a class="header-anchor" href="#success-looks-like" aria-label="Permalink to &quot;Success looks like&quot;">​</a></h2><p>A user correctly explains why geostationary satellites are at 35,786 km and not higher or lower after using this screen.</p><p>A user is surprised to discover that JWST is not in Earth orbit at all — it&#39;s at a Lagrange point 1.5 million km away — and that discovery changes their understanding of what &quot;Webb telescope&quot; means.</p><h2 id="out-of-scope" tabindex="-1">Out of scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of scope&quot;">​</a></h2><ul><li>Orbital mechanics simulation (objects don&#39;t move — this is a static reference view)</li><li>Debris cloud or Kessler syndrome visualisation</li><li>Live satellite tracking (TLE data)</li><li>Objects below ISS altitude (suborbital flights)</li></ul><h2 id="the-sharpest-threat" tabindex="-1">The sharpest threat <a class="header-anchor" href="#the-sharpest-threat" aria-label="Permalink to &quot;The sharpest threat&quot;">​</a></h2><p>The logarithmic scale is the screen&#39;s core insight. If it isn&#39;t labelled clearly enough that a first-time user understands why the scale is non-linear, the screen looks like a random arrangement of dots rather than a carefully scaled diagram.</p><h2 id="open-threads" tabindex="-1">Open threads <a class="header-anchor" href="#open-threads" aria-label="Permalink to &quot;Open threads&quot;">​</a></h2><ul><li>UXS-005 for full visual contract</li><li>Earth objects data from <code>data/earth-objects.json</code> (RFC-002 adjacent — same data model questions apply)</li></ul><h2 id="links" tabindex="-1">Links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;Links&quot;">​</a></h2><ul><li>Prototype: <code>docs/prototypes/P05_earth-orbit.html</code></li><li>Concept: <code>docs/concept/02_Project_Concept.md §six-screens</code></li></ul>',22)])])}const b=t(o,[["render",s]]);export{p as __pageData,b as default};
